import{_ as t,o as a,c as i,a2 as o}from"./chunks/framework.OWFDNrRT.js";const u=JSON.parse('{"title":"ADR-009: Runtime Orchestration via ModPlatform","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-009-runtime-orchestration.md","filePath":"adr/ADR-009-runtime-orchestration.md","lastUpdated":1773459185000}'),n={name:"adr/ADR-009-runtime-orchestration.md"};function r(l,e,s,d,c,g){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="adr-009-runtime-orchestration-via-modplatform" tabindex="-1">ADR-009: Runtime Orchestration via ModPlatform <a class="header-anchor" href="#adr-009-runtime-orchestration-via-modplatform" aria-label="Permalink to &quot;ADR-009: Runtime Orchestration via ModPlatform&quot;">​</a></h1><p><strong>Status</strong>: Accepted <strong>Date</strong>: 2026-03-10 <strong>Deciders</strong>: kooshapari</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>All major SDK, Bridge, UI, and HMR components existed as isolated pieces:</p><ul><li><strong>SDK</strong>: Pack loading, registry system, schema validation, dependency resolution</li><li><strong>Bridge</strong>: ECS glue layer translating SDK operations into game state changes</li><li><strong>UI</strong>: F10 mod menu overlay, F9 debug overlay</li><li><strong>HMR</strong>: File watching and hot reload of YAML pack content</li></ul><p>Each component worked independently but there was no central coordinator connecting them into a coherent lifecycle. Plugin.cs had to manually wire everything together, leading to fragile initialization ordering, scattered error handling, and difficulty testing the full pipeline.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Create a <code>ModPlatform</code> class that owns the entire mod platform lifecycle:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Initialize -&gt; OnWorldReady -&gt; LoadPacks -&gt; StartHotReload -&gt; Shutdown</span></span></code></pre></div><p>Key design choices:</p><ul><li><strong>ModPlatform is not a MonoBehaviour</strong>. It is a plain C# class instantiated by <code>Plugin.cs</code> and given Unity callbacks (Update, OnDestroy) by the plugin.</li><li><strong>Plugin.cs stays thin</strong>. It creates <code>ModPlatform</code>, forwards Unity lifecycle events, and does nothing else.</li><li><strong>Single entry point</strong> for all mod platform features. SDK, Bridge, UI, and HMR are initialized and coordinated through ModPlatform.</li><li><strong>Lifecycle phases</strong> are explicit: <ul><li><code>Initialize()</code>: Set up logging, load configuration, create SDK services</li><li><code>OnWorldReady(World)</code>: Called when ECS World is available; initialize Bridge, enumerate systems/entities</li><li><code>LoadPacks()</code>: Discover packs, validate, resolve dependencies, apply to registries via Bridge</li><li><code>StartHotReload()</code>: Begin file watching, wire change events to re-validation and re-application</li><li><code>Shutdown()</code>: Stop HMR, flush state, clean up</li></ul></li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li><strong>Single entry point</strong>: All mod platform behavior flows through ModPlatform, making it easy to understand the full initialization sequence.</li><li><strong>Plugin.cs stays thin</strong>: The BepInEx plugin class contains only bootstrap glue, not business logic.</li><li><strong>Testable</strong>: ModPlatform can be instantiated in tests with a mock World, without requiring BepInEx or Unity runtime. Each lifecycle phase can be tested independently.</li><li><strong>Clear error boundaries</strong>: Each phase has its own error handling. A failure in LoadPacks does not prevent the debug overlay from working.</li><li><strong>Ordering guarantees</strong>: Components that depend on ECS World availability are only initialized after OnWorldReady, eliminating null-World race conditions.</li><li><strong>HMR integration</strong>: Hot reload is a first-class lifecycle phase rather than an afterthought bolted onto Plugin.cs.</li></ul>',13)])])}const p=t(n,[["render",r]]);export{u as __pageData,p as default};
